operator fun <T> get(expression: Expression<T>): T {
    val column = expression as? Column<*>
    return when {
        column?.isEntityIdentifier() == true && column.table is CompositeIdTable -> {
            val resultID = CompositeID {
                column.table.idColumns.forEach { column ->
                    it[column as Column<EntityID<Any>>] = getInternal(column, checkNullability = true).value
                }
            }
            EntityID(resultID, column.table) as T
        }
        column?.isJsonBColumnForCasting() == true -> try {
            val castExpression = CastToJson(column, column.columnType)
            getInternal(castExpression, checkNullability = true) as T
        } catch (_: IllegalStateException) {
            // DAO may cache an entity after insert with only its column field values cached
            getInternal(expression, checkNullability = true)
        }
        else -> getInternal(expression, checkNullability = true)
    }
}

override fun unlock(owner: Any?) {
    while (true) {
        // Is this mutex locked?
        check(isLocked) { "This mutex is not locked" }
        // Read the owner, waiting until it is set in a spin-loop if required.
        val curOwner = this.owner.value
        if (curOwner === NO_OWNER) continue // <-- ATTENTION, BLOCKING PART HERE
        // Check the owner.
        check(curOwner === owner || owner == null) { "This mutex is locked by $curOwner, but $owner is expected" }
        // Try to clean the owner first. We need to use CAS here to synchronize with concurrent `unlock(..)`-s.
        if (!this.owner.compareAndSet(curOwner, NO_OWNER)) continue
        // Release the semaphore permit at the end.
        release()
        return
    }
}

private fun tryLockImpl(owner: Any?): Int {
    while (true) {
        if (tryAcquire()) {
            assert { this.owner.value === NO_OWNER }
            this.owner.value = owner
            return TRY_LOCK_SUCCESS
        } else {
            // The semaphore permit acquisition has failed.
            // However, we need to check that this mutex is not
            // locked by our owner.
            if (owner == null) return TRY_LOCK_FAILED
            when (holdsLockImpl(owner)) {
                // This mutex is already locked by our owner.
                HOLDS_LOCK_YES -> return TRY_LOCK_ALREADY_LOCKED_BY_OWNER
                // This mutex is locked by another owner, `trylock(..)` must return `false`.
                HOLDS_LOCK_ANOTHER_OWNER -> return TRY_LOCK_FAILED
                // This mutex is no longer locked, restart the operation.
                HOLDS_LOCK_UNLOCKED -> continue
            }
        }
    }
}

internal class NullableSerializer<T : Any>(private val serializer: KSerializer<T>) : KSerializer<T?> {
    override val descriptor: SerialDescriptor = SerialDescriptorForNullable(serializer.descriptor)

    override fun serialize(encoder: Encoder, value: T?) {
        if (value != null) {
            encoder.encodeNotNullMark()
            encoder.encodeSerializableValue(serializer, value)
        } else {
            encoder.encodeNull()
        }
    }

    override fun deserialize(decoder: Decoder): T? {
        return if (decoder.decodeNotNullMark()) decoder.decodeSerializableValue(serializer) else decoder.decodeNull()
    }

    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other == null || this::class != other::class) return false
        other as NullableSerializer<*>
        if (serializer != other.serializer) return false
        return true
    }

    override fun hashCode(): Int {
        return serializer.hashCode()
    }
}

public data class AndRouteSelector(
    val first: RouteSelector,
    val second: RouteSelector
) : RouteSelector(), CompositeRouteSelector {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        val result1 = first.evaluate(context, segmentIndex)
        if (result1 !is RouteSelectorEvaluation.Success) {
            return result1
        }
        val result2 = second.evaluate(context, segmentIndex + result1.segmentIncrement)
        if (result2 !is RouteSelectorEvaluation.Success) {
            return result2
        }
        val resultValues = result1.parameters + result2.parameters
        return RouteSelectorEvaluation.Success(
            result1.quality * result2.quality,
            resultValues,
            result1.segmentIncrement + result2.segmentIncrement
        )
    }

    override fun subSelectors(): List<RouteSelector> =
        listOf(first, second)

    override fun toString(): String = "{$first & $second}"
}

private fun parse(path: String): List<String> {
    if (path.isEmpty() || path == "/") return emptyList()
    val length = path.length
    var beginSegment = 0
    var nextSegment = 0
    val segmentCount = path.count { it == '/' }
    val segments = ArrayList<String>(segmentCount)
    while (nextSegment < length) {
        nextSegment = path.indexOf('/', beginSegment)
        if (nextSegment == -1) {
            nextSegment = length
        }
        if (nextSegment == beginSegment) {
            // empty path segment, skip it
            beginSegment = nextSegment + 1
            continue
        }
        val segment = path.decodeURLPart(beginSegment, nextSegment)
        segments.add(segment)
        beginSegment = nextSegment + 1
    }
    if (!call.ignoreTrailingSlash && path.endsWith("/")) {
        segments.add("")
    }
    return segments
}

