  beginControlFlow("if (%L.%M($customScalarAdapters.falseVariables, $typenameLiteral, $customScalarAdapters.deferredFragmentIdentifiers, $pathLiteral))", property.condition.codeBlock(), evaluate)
  add("$reader.rewind()\n")
} else {
  checkedProperties.add(property.info.responseName)
  add("$reader.rewind()\n")
  add("val ")
}

if (nsError != null) {
  if (disposed.compareAndSet(expect = false, update = true)) {
    @Suppress("REDUNDANT_CALL_OF_CONVERSION_METHOD")
    val exception = if (nsError.domain == "NSPOSIXErrorDomain" && nsError.code.toLong() == ENOTCONN.toLong()) {
      ApolloWebSocketClosedException(nsurlSessionWebSocketTask.closeCode.convert(), nsurlSessionWebSocketTask.closeReason?.toByteString()
          ?.toByteArray()?.commonToUtf8String())
    } else {
      ApolloNetworkException("Error reading websocket: ${nsError.localizedDescription}", platformCause = nsError)
    }
    listener.onError(exception)
  }
} else if (message != null) {
  when (message.type) {
    NSURLSessionWebSocketMessageTypeData -> {
      listener.onMessage(message.data!!.toByteString().toByteArray())
    }

    NSURLSessionWebSocketMessageTypeString -> {
      listener.onMessage(message.string!!)
    }
  }

  receiveNext()
}

if (maxResumeCount > 0) { // collect emitters to resume if we have them
            resumes = arrayOfNulls(maxResumeCount)
            var resumeCount = 0
            val buffer = buffer!!
            for (curEmitterIndex in newBufferEndIndex until newQueueEndIndex) {
                val emitter = buffer.getBufferAt(curEmitterIndex)
                if (emitter !== NO_VALUE) {
                    emitter as Emitter // must have Emitter class
                    resumes[resumeCount++] = emitter.cont
                    buffer.setBufferAt(curEmitterIndex, NO_VALUE) // make as canceled if we moved ahead
                    buffer.setBufferAt(newBufferEndIndex, emitter.value)
                    newBufferEndIndex++
                    if (resumeCount >= maxResumeCount) break // enough resumed, done
                }
            }
        }

try {
    var fairnessCounter = 0
    while (true) {
        try {
            currentTask.run()
        } catch (e: Throwable) {
            handleCoroutineException(EmptyCoroutineContext, e)
        }
        currentTask = obtainTaskOrDeallocateWorker() ?: return
        // 16 is our out-of-thin-air constant to emulate fairness. Used in JS dispatchers as well
        if (++fairnessCounter >= 16 && dispatcher.safeIsDispatchNeeded(this@LimitedDispatcher)) {
            // Do "yield" to let other views execute their runnable as well
            // Note that we do not decrement 'runningWorkers' as we are still committed to our part of work
            dispatcher.safeDispatch(this@LimitedDispatcher, this)
            return
        }
    }
} catch (e: Throwable) {
    // If the worker failed, we should deallocate its slot
    synchronized(workerAllocationLock) {
        runningWorkers.decrementAndGet()
    }
    throw e
}

if (bidirectional) {
  val upstreamProject = when (dependencyNotation) {
    is ProjectDependency -> project.project(dependencyNotation.getPathCompat())
    is Project -> dependencyNotation
    else -> error("dependsOn(dependencyNotation, true) requires a Project or ProjectDependency")
  }

  upstreamProject.plugins.withId("com.apollographql.apollo") {
    val apolloExtension = upstreamProject.extensions.findByType(ApolloExtension::class.java) as? DefaultApolloExtension
    check(apolloExtension != null) {
      "Cannot find 'apollo' extension in upstream project ${upstreamProject.name} (registered: ${upstreamProject.extensions})"
    }
    apolloExtension.registerDownstreamProject(name, project.path)
  }
}

if ((project.name != "html-widgets") && (project.name != "html-integration-widgets")) {
    afterEvaluate {
        if (plugins.hasPlugin("org.jetbrains.kotlin.multiplatform")) {
            project.extensions.getByType<KotlinMultiplatformExtension>().apply {
                targets.configureEach {
                    compilations.configureEach {
                        compileTaskProvider.configure {
                            compilerOptions {
                                allWarningsAsErrors.set(false)
                                freeCompilerArgs.addAll(
                                    // see https://kotlinlang.org/docs/opt-in-requirements.html
                                    "-opt-in=kotlin.RequiresOptIn"
                                )
                            }
                        }
                    }
                }
            }
        }
    }
}

if (targetLanguage == TargetLanguage.JAVA) {
  sourceOutput = sourceOutput plus JavaCodegen.buildOperationsSources(
      irOperations = irOperations,
      operationOutput = operationOutput,
      upstreamCodegenMetadatas = upstreamCodegenMetadata + listOfNotNull(sourceOutput?.codegenMetadata),
      codegenOptions = codegenOptions,
      layout = layout,
      javaOutputTransform = javaOutputTransform,
  ).toSourceOutput()
} else {
  sourceOutput = sourceOutput plus KotlinCodegen.buildOperationSources(
      targetLanguage = targetLanguage,
      irOperations = irOperations,
      operationOutput = operationOutput,
      upstreamCodegenMetadata = upstreamCodegenMetadata + listOfNotNull(sourceOutput?.codegenMetadata),
      codegenOptions = codegenOptions,
      layout = layout,
      kotlinOutputTransform = kotlinOutputTransform
  ).toSourceOutput()
}

if (fragment.interfaceModelGroup != null) {
  // responseBase, we should generate the implementations here
  fragment.dataModelGroup.maybeFlatten(flatten).flatMap { it.models }.map {
    ModelBuilder(
        context = context,
        model = it,
        superClassName = if (it.id == fragment.dataModelGroup.baseModelId) {
          context.resolver.resolveSchemaType(fragment.typeCondition).nestedClass(Identifier.Data)
        } else {
          null
        },
        path = listOf(packageName, simpleName),
        hasSubclassesInSamePackage = true,
        adaptableWith = null,
        reservedNames = setOf("Companion")
    )
  }
} else {
  // The data models are written outside the fragment
  emptyList()
}
